# PCA testfrom loaders.raman_loader import select_directory, select_file, load_ramanfrom preprocessors.raman_preprocess import preprocess_pipeline_1, preprocess_pipeline_2, group_preprocess, group_preprocess_2, avg_y_blockfrom preprocessors.aligner import align_xyimport osimport pandas as pdfrom models.wrappers import PCA_modelfrom plotting.plot_PCA import plot_pca_loadings# === Select and Create Directories ===print("\n📂 Select the directory containing your raw Raman .spc files:")#directory = select_directory()directory= "/Users/bp/Desktop/Seriola_Model/test/"spectra_dir = os.path.join(directory, "Raman_Spectra")results_dir = os.path.join(directory, "Model_Results")os.makedirs(spectra_dir, exist_ok=True)os.makedirs(results_dir, exist_ok=True)# === Load Raw Raman Spectra (X Block) ===sample_spectra, shifts, sample_groups = load_raman(directory, spectra_dir)# === Preprocess Spectra ===preprocessed_sample_spectra, cropped_axis = preprocess_pipeline_2(sample_spectra, spectra_dir)# === Step 5: Load Reference Data (Y Block) ===print("\n📄 Select the reference data file:")#gcms_path = select_file()gcms_path = "/Users/bp/Desktop/Seriola_Model/GCMS_Data/250716_classes.xlsx"gcms_df = pd.read_excel(gcms_path)gcms_df.set_index('ID', inplace=True)gcms_group_df = avg_y_block(gcms_df) #use for group averaging preprocessing methods# === Align X and Y Blocks ===filtered_X, filtered_Y, filtered_sample_ids, filtered_groups, classes, unmatched_ids  = align_xy(preprocessed_sample_spectra, gcms_df)# === Run PCA ===pca_results = PCA_model(    X=filtered_X,    classes=classes,    axis=cropped_axis,    directory=results_dir,    n_components=5,    show_ellipses=True,    ellipse_alpha=0.25  # Adjust for visibility)plot_pca_loadings(    pca_model=pca_results["pca_model"],    axis=cropped_axis,    directory=results_dir,    components=[0, 1],    top_n=4  # label top bands per PC)